2654	fn load_skills_from_roots(roots: &[SkillRoot]) -> std::io::Result<Vec<SkillSummary>> {
2655	    let mut skills = Vec::new();
2656	    let mut active_sources = BTreeMap::<String, DefinitionSource>::new();
2657	
2658	    for root in roots {
2659	        let mut root_skills = Vec::new();
2660	        for entry in fs::read_dir(&root.path)? {
2661	            let entry = entry?;
2662	            match root.origin {
2663	                SkillOrigin::SkillsDir => {
2664	                    if !entry.path().is_dir() {
2665	                        continue;
2666	                    }
2667	                    let skill_path = entry.path().join("SKILL.md");
2668	                    if !skill_path.is_file() {
2669	                        continue;
2670	                    }
2671	                    let contents = fs::read_to_string(skill_path)?;
2672	                    let (name, description) = parse_skill_frontmatter(&contents);
2673	                    root_skills.push(SkillSummary {
2674	                        name: name
2675	                            .unwrap_or_else(|| entry.file_name().to_string_lossy().to_string()),
2676	                        description,
2677	                        source: root.source,
2678	                        shadowed_by: None,
2679	                        origin: root.origin,
2680	                    });
2681	                }
2682	                SkillOrigin::LegacyCommandsDir => {
2683	                    let path = entry.path();
2684	                    let markdown_path = if path.is_dir() {
2685	                        let skill_path = path.join("SKILL.md");
2686	                        if !skill_path.is_file() {
2687	                            continue;
2688	                        }
2689	                        skill_path
2690	                    } else if path
2691	                        .extension()
2692	                        .is_some_and(|ext| ext.to_string_lossy().eq_ignore_ascii_case("md"))
2693	                    {
2694	                        path
2695	                    } else {
2696	                        continue;
2697	                    };
2698	
2699	                    let contents = fs::read_to_string(&markdown_path)?;
2700	                    let fallback_name = markdown_path.file_stem().map_or_else(
2701	                        || entry.file_name().to_string_lossy().to_string(),
2702	                        |stem| stem.to_string_lossy().to_string(),
2703	                    );
2704	                    let (name, description) = parse_skill_frontmatter(&contents);
2705	                    root_skills.push(SkillSummary {
2706	                        name: name.unwrap_or(fallback_name),
2707	                        description,
2708	                        source: root.source,
2709	                        shadowed_by: None,
2710	                        origin: root.origin,
2711	                    });
2712	                }
2713	            }
2714	        }
2715	        root_skills.sort_by(|left, right| left.name.cmp(&right.name));
2716	
2717	        for mut skill in root_skills {
2718	            let key = skill.name.to_ascii_lowercase();
2719	            if let Some(existing) = active_sources.get(&key) {
2720	                skill.shadowed_by = Some(*existing);
2721	            } else {
2722	                active_sources.insert(key, skill.source);
2723	            }
2724	            skills.push(skill);
2725	        }
2726	    }
2727	
2728	    Ok(skills)
2729	}
