2731	fn parse_toml_string(contents: &str, key: &str) -> Option<String> {
2732	    let prefix = format!("{key} =");
2733	    for line in contents.lines() {
2734	        let trimmed = line.trim();
2735	        if trimmed.starts_with('#') {
2736	            continue;
2737	        }
2738	        let Some(value) = trimmed.strip_prefix(&prefix) else {
2739	            continue;
2740	        };
2741	        let value = value.trim();
2742	        let Some(value) = value
2743	            .strip_prefix('"')
2744	            .and_then(|value| value.strip_suffix('"'))
2745	        else {
2746	            continue;
2747	        };
2748	        if !value.is_empty() {
2749	            return Some(value.to_string());
2750	        }
2751	    }
2752	    None
